+/// ":nospecial [count] {cmd} {arg}...": Execute an ex command with literal arguments.
+/// Count indicates how many space-separated arguments to collect:
+///   :nospecial cmd arg        - invokes :cmd with literal arg
+///   :2nospecial cmd arg1 arg2 - invokes :cmd with literal arg1 and arg2 (split at 2 spaces)
+/// Arguments are passed literally without any escaping or special character handling.
+static void ex_nospecial(exarg_T *eap)
+{
+  char *arg = eap->arg;
+  
+  // Skip initial whitespace to find the command name
+  while (*arg == ' ') {
+    arg++;
+  }
+  if (*arg == NUL) {
+    emsg(_("E471: Argument required"));
+    return;
+  }
+  
+  // Find the end of the command name (first space)
+  char *cmd_end = arg;
+  while (*cmd_end != NUL && *cmd_end != ' ') {
+    cmd_end++;
+  }
+  
+  char *cmd_name = xmemdupz(arg, (size_t)(cmd_end - arg));
+  
+  // Skip spaces after command
+  while (*cmd_end == ' ') {
+    cmd_end++;
+  }
+  
+  // Determine how many arguments to collect before the remainder
+  int split_count = 1;  // default: just the command
+  if (eap->addr_count > 0 && eap->line1 >= 1) {
+    split_count = (int)eap->line1;
+  }
+  
+  // Build argument list by splitting at spaces up to split_count
+  char *p = cmd_end;
+  int parts_collected = 0;
+  garray_T cmd_parts;
+  ga_init(&cmd_parts, (int)sizeof(char *), 10);
+  
+  // Collect split_count arguments (not including the command itself)
+  while (*p != NUL && parts_collected < split_count) {
+    // Skip leading spaces
+    while (*p == ' ') {
+      p++;
+    }
+    if (*p == NUL) {
+      break;
+    }
+    
+    // Find end of this argument
+    char *arg_start = p;
+    while (*p != NUL && *p != ' ') {
+      p++;
+    }
+    
+    // Store this argument
+    char *arg_copy = xmemdupz(arg_start, (size_t)(p - arg_start));
+    GA_APPEND(char *, &cmd_parts, arg_copy);
+    parts_collected++;
+  }
+  
+  // The remainder after split_count arguments (kept as-is, preserving spaces)
+  while (*p == ' ' && parts_collected < split_count) {
+    p++;
+  }
+  
+  // Build the final command: :cmd_name arg1 arg2 ... [remainder]
+  garray_T final_cmd;
+  ga_init(&final_cmd, (int)sizeof(char), 256);
+  
+  // Add command name
+  ga_concat(&final_cmd, cmd_name);
+  
+  // Add collected arguments
+  for (int i = 0; i < cmd_parts.ga_len; i++) {
+    ga_append(&final_cmd, ' ');
+    char *collected_arg = ((char **)cmd_parts.ga_data)[i];
+    ga_concat(&final_cmd, collected_arg);
+  }
+  
+  // Add remainder if present
+  if (*p != NUL) {
+    ga_append(&final_cmd, ' ');
+    ga_concat(&final_cmd, p);
+  }
+  
+  ga_append(&final_cmd, NUL);
+  
+  // Execute the command
+  do_cmdline_cmd(final_cmd.ga_data);
+  
+  // Cleanup
+  xfree(cmd_name);
+  for (int i = 0; i < cmd_parts.ga_len; i++) {
+    xfree(((char **)cmd_parts.ga_data)[i]);
+  }
+  ga_clear(&cmd_parts);
+  ga_clear(&final_cmd);
+}
